import{c as a,Q as r,j as i,m as t}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I archive or unarchive a release?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/archive-release.md","filePath":"guide/recipes/admin/archive-release.md","lastUpdated":1779094756000}'),o={name:"guide/recipes/admin/archive-release.md"};function l(s,e,n,h,d,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="how-do-i-archive-or-unarchive-a-release" tabindex="-1">How do I archive or unarchive a release? <a class="header-anchor" href="#how-do-i-archive-or-unarchive-a-release" aria-label="Permalink to &quot;How do I archive or unarchive a release?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>Archiving hides a finished release from the default list. It&#39;s a clean-up action — no impact on what&#39;s deployed. You have 30 days to unarchive before per-service config and logs are purged.</p><h2 id="to-archive" tabindex="-1">To archive <a class="header-anchor" href="#to-archive" aria-label="Permalink to &quot;To archive&quot;">​</a></h2><ol><li>Open the release detail page.</li><li>Click <strong>Archive</strong> in the actions menu (top right).</li><li>Confirm.</li></ol><h2 id="to-unarchive-within-30-days" tabindex="-1">To unarchive (within 30 days) <a class="header-anchor" href="#to-unarchive-within-30-days" aria-label="Permalink to &quot;To unarchive (within 30 days)&quot;">​</a></h2><ol><li>On the Releases page, change the filter to show <strong>Archived</strong>.</li><li>Open the release detail page.</li><li>Click <strong>Unarchive</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><ul><li>Archived releases are hidden from the default Releases view.</li><li>The detail page shows the archive date and the unarchive deadline.</li><li>After 30 days, per-service configuration, environment-version pins, and pipeline logs are permanently purged. The release record itself remains (for audit) with a &quot;purged&quot; badge.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./rollback-release">How do I roll back a release?</a></li></ul>',11)])])}const v=a(o,[["render",l]]);export{p as __pageData,v as default};
